={
  "model": "ibm/granite-docling",
  "prompt": "Perform layout-aware document boundary detection across pages. Identify boundary starts based on: page number reset to 1/01/I, new recipient address block, new addressee, date change, branding shift. Return JSON array of boundary page indexes.",
  "stream": false
}

parameters.functionCode:
const { PDFDocument } = require('pdf-lib');
const fs = require('fs');
const path = require('path');

const buffer = Buffer.from(items[0].binary.data.data);
const pdfDoc = await PDFDocument.load(buffer);
const pageCount = pdfDoc.getPageCount();

let boundaries = [];
try {
  const parsed = JSON.parse($json.response);
  boundaries = parsed;
} catch {
  return items;
}

if (!Array.isArray(boundaries) || boundaries.length === 0) return items;

boundaries.sort((a,b)=>a-b);
boundaries.push(pageCount);

let start = 0;
let part = 1;

const outputDir = 'D:/EPSCAN/Processed';
if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir);

for (const boundary of boundaries) {
  const newDoc = await PDFDocument.create();
  const pages = await newDoc.copyPages(pdfDoc, Array.from({length: boundary-start}, (_,i)=>i+start));
  pages.forEach(p=>newDoc.addPage(p));

  const bytes = await newDoc.save();
  const base = path.basename($json.filePath, '.pdf');
  fs.writeFileSync(`${outputDir}/${base}_part${part}.pdf`, bytes);

  start = boundary;
  part++;
}

return items;
